/**
 * @summary List all merchants
 */
export const getListMerchantsUrl = (params?: ListMerchantsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/merchants?${stringifiedParams}`
    : `/api/merchants`;
};

export const listMerchants = async (
  params?: ListMerchantsParams,
  options?: RequestInit,
): Promise<Merchant[]> => {
  return customFetch<Merchant[]>(getListMerchantsUrl(params), {
    ...options,
    method: "GET",
  });
};

